// Learn: Require subclasses to implement an abstract method.
abstract class Shape {
  abstract double area();
}

class Circle extends Shape {
  private final double radius;

  Circle(double radius) {
    this.radius = radius;
  }

  @Override
  double area() {
    // Circle supplies the area formula required by Shape.
    return Math.PI * radius * radius;
  }
}
